import os
import pandas as pd
def task_func(filename: str) -> pd.DataFrame:
    if not os.path.exists(filename):
        raise FileNotFoundError(f"No such file: '{filename}'")

    if os.stat(filename).st_size == 0:
        return pd.DataFrame()

    df = pd.read_csv(filename)

    with open(filename, 'w') as file:
        file.truncate()

    return df

